import fs from "fs";
import {
  buildPolyglotFnInput,
  id,
  callArg,
  member,
  varDecl,
  ret,
} from './src/betti/polyglot-betti-bridge';

const input = buildPolyglotFnInput(
  'typescript',
  'heavy_compute_pipeline',
  ['dataset', 'config'],
  [
    varDecl(['cleaned'], callArg(member(id('dataset'), 'filter'), [id('config')])),
    varDecl(['mapped'], callArg(id('apply_transform'), [id('cleaned')])),
    varDecl(['reduced'], callArg(id('aggregate'), [id('mapped')])),
    ret(id('reduced'))
  ]
);

fs.writeFileSync("native_sorted.json", JSON.stringify(input));
console.log("JSON written successfully to native_sorted.json!");
